--- Makefile	(revision 336929)
+++ Makefile	(working copy)
@@ -38,8 +38,8 @@

 # Workaround to build and segfault on > 10.x
 .if ${OPSYS} == "FreeBSD" && ${OSVERSION} >= 1000000
-USE_GCC=	yes
-LDFLAGS+=	-lc++
+CXXFLAGS+=-std=c++11
+EXTRA_PATCHES+=${PATCHDIR}/extra-patch-fix-clang-build.diff
 .endif

 .if ${PORT_OPTIONS:MXMLRPC}
